package com.lugatek.thubanlodestar.widgets;
import android.content.*;import android.graphics.*;import android.util.*;import android.view.*;import java.util.*;
public class ColumnGraphView extends View{ Paint p=new Paint(1),t=new Paint(1); ArrayList<Float> vals=new ArrayList<>(); public ColumnGraphView(Context c){super(c);init();} public ColumnGraphView(Context c,AttributeSet a){super(c,a);init();} void init(){p.setColor(Color.rgb(255,177,68));t.setColor(Color.WHITE);t.setTextSize(34);setMinimumHeight(150);} public void add(float v){vals.add(v);while(vals.size()>45)vals.remove(0);invalidate();} protected void onDraw(Canvas c){c.drawColor(Color.rgb(18,24,33));int w=getWidth(),h=getHeight();float max=1;for(float v:vals)max=Math.max(max,Math.abs(v));float bw=w/50f;for(int i=0;i<vals.size();i++){float v=vals.get(i);float bh=(Math.abs(v)/max)*(h-38);float x=i*bw*1.1f;c.drawRect(x,h-bh,x+bw,h,p);} if(vals.size()>0)c.drawText(String.format("Sapma %.1f µT",vals.get(vals.size()-1)),16,36,t);} }
